/**
 * Corrige valores monetários no formato "R$2" para "R$ 2" em uma string.
 * @param {string} value - A string que pode conter valores monetários.
 * @returns {string} - A string corrigida.
 */
function formatCurrency(value) {
    if (typeof value !== 'string') {
        return value; // Retorna o valor original se não for uma string
    }

    // Adiciona um espaço após "R$" se não houver um já presente
    return value.replace(/R\$(\d)/g, 'R$ $1');
}

/**
 * Percorre recursivamente um objeto ou array e corrige valores monetários.
 * @param {object|array} data - O objeto ou array a ser processado.
 * @returns {object|array} - O objeto ou array corrigido.
 */
function formatCurrencyInJson(data) {
    if (Array.isArray(data)) {
        // Se for um array, aplica a função a cada item
        return data.map(item => formatCurrencyInJson(item));
    } else if (typeof data === 'object' && data !== null) {
        // Se for um objeto, percorre suas propriedades
        for (const key in data) {
            data[key] = formatCurrencyInJson(data[key]);
        }
    } else if (typeof data === 'string') {
        // Se for uma string, aplica a formatação
        return formatCurrency(data);
    }
    return data;
}

// Obtém os dados de entrada do n8n
const jsonData = $input.all();

// Aplica a correção no JSON
const formattedJson = jsonData.map(item => ({
    json: formatCurrencyInJson(item.json)
}));

// Retorna os dados no formato esperado pelo n8n
return formattedJson;

// Obtém os dados de entrada do N8n
let inputData = $input.all();

// Processa cada item individualmente
let outputData = inputData.map(item => {
    // Garante que o item tenha a estrutura correta
    let json = item.json || {};

    // Verifica se a chave query e respondent existem
    if (json.query && json.query.respondent) {
        try {
            // Converte a string JSON de respondent para um objeto
            let respondent = JSON.parse(json.query.respondent);

            // Função para escapar aspas simples dentro do objeto
            function escapeSingleQuotes(obj) {
                if (typeof obj === 'string') {
                    return obj.replace(/'/g, "''"); // Substitui ' por ''
                } else if (Array.isArray(obj)) {
                    return obj.map(escapeSingleQuotes);
                } else if (typeof obj === 'object' && obj !== null) {
                    return Object.fromEntries(
                        Object.entries(obj).map(([key, value]) => [key, escapeSingleQuotes(value)])
                    );
                }
                return obj;
            }

            // Aplica a função de escape no objeto respondent
            let escapedRespondent = escapeSingleQuotes(respondent);

            // Atualiza a chave query.respondent sem modificar diretamente
            json = {
                ...json,
                query: {
                    ...json.query,
                    respondent: JSON.stringify(escapedRespondent)
                }
            };

        } catch (error) {
            throw new Error("Erro ao processar query.respondent: " + error.message);
        }
    }

    // Retorna o item no formato esperado pelo N8n
    return { json };
});

// Retorna os dados processados
return outputData;

